# Helper function to generate cache keys
def generate_cache_key(prefix, *args, **kwargs):
    key_data = f"{prefix}:{':'.join(map(str, args))}:{json.dumps(kwargs, sort_keys=True)}"
    return hashlib.md5(key_data.encode()).hexdigest()

# Database helper functions
def get_db_connection():
    conn = sqlite3.connect('app.db')
    conn.row_factory = sqlite3.Row
    return conn

def dict_from_row(row):
    return dict(zip(row.keys(), row))

# Cache decorator for database queries
def cache_db_query(ttl=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = generate_cache_key(func.__name__, *args, **kwargs)
            
            # Try to get from cache
            cached_result = memcache_client.get(cache_key)
            if cached_result is not None:
                print(f"Cache HIT for key: {cache_key}")
                return cached_result
            
            print(f"Cache MISS for key: {cache_key}")
            # Execute the function and cache the result
            result = func(*args, **kwargs)
            memcache_client.set(cache_key, result, expire=ttl)
            return result
        
        wrapper.__name__ = func.__name__
        return wrapper
    return decorator

# Cache decorator for API responses
def cache_api_response(ttl=60):
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Generate cache key from request path and query parameters
            cache_key = generate_cache_key(
                func.__name__,
                request.path,
                request.args.to_dict()
            )
            
            # Try to get from cache
            cached_result = memcache_client.get(cache_key)
            if cached_result is not None:
                print(f"API Cache HIT for key: {cache_key}")
                return jsonify(cached_result), 200
            
            print(f"API Cache MISS for key: {cache_key}")
            # Execute the function and cache the result
            result = func(*args, **kwargs)
            
            # Only cache successful responses
            if isinstance(result, tuple):
                response_data, status_code = result
                if status_code == 200:
                    memcache_client.set(cache_key, response_data, expire=ttl)
            else:
                memcache_client.set(cache_key, result, expire=ttl)
            
            return result
        
        wrapper.__name__ = func.__name__
        return wrapper
    return decorator

# Cached database query functions
@cache_db_query(ttl=300)  # Cache for 5 minutes
def get_user_by_id(user_id):
    conn = get_db_connection()
    user = conn.execute('SELECT * FROM users WHERE id = ?', (user_id,)).fetchone()
    conn.close()
    
    if user:
        return dict_from_row(user)
    return None

@cache_db_query(ttl=600)  # Cache for 10 minutes
def get_all_users():
    conn = get_db_connection()
    users = conn.execute('SELECT * FROM users').fetchall()
    conn.close()
    
    return [dict_from_row(user) for user in users]

